{
  "request_id": "REQUEST_ID",  // Unique identifier of the request. The client is responsible to create this value.
  "user": {  // User who gets recommended products or product ads.
    "user_id": "USER_ID",  // User identifier used by the platform. This should typically be the sign-in ID used within the platform, and is highly recommended to be hashed prior to being sent to Moloco. Please provide this value whenever available to achieve optimal performance. If the value is unknown for any reason, please leave empty and do not fill in a default or random value.
    "interests": [  // Interests of the user. e.g. ['sports', 'outdoor']
      "INTEREST"
    ]
  },
  "device": {
    "os": "OS",  // OS of the device. For app traffic, 'ios', 'android' should be provided. When `advertising_id` is provided, this field also should be specified.
    "os_version": "OS_VERSION",  // OS version which is taken from the device without manipulation or normalization. (e.g., '14.4.1')
    "model": "MODEL",  // Device model, which is taken from the device without manipulation or normalization. (e.g., 'iPhone 11 Pro')
    "persistent_id": "PERSISTENT_ID"  // Alternative ID to track users regardless of sign-in status. This can typically be an ID associated with the device that the user is on, and is highly recommended to be hashed prior to being sent to Moloco. Please provide this value in addition to the user.user_id whenever available to achieve optimal performance. If the value is unknown for any reason, please leave empty and do not fill in a default or random value. For further information, please refer to this guide: https://mcm-docs.moloco.com/docs/generating-persistent-identifiers
  },
  "custom_id": "CUSTOM_ID",  // Alternative ID to track users regardless of sign-in status or device. This ID should be provided as a third option following the user.user_id and device.persistent_id, and is highly recommended to be hashed prior to being sent to Moloco. This ID must be provided if both the user.user_id and device.persistent_id fields are left empty. Please do not fill in a default value, and instead randomize it if you must, but we recommend you send some ID that can be used to track users even if for a short time span. Please reach out to Moloco if you have further questions about this ID.
  "inventories": [
    {  // Inventory where the ads will be displayed.
      "inventory_id": "INVENTORY_ID",  // A unique identifier for the inventory that the platform manage. It is used for ad decision, analytics, reporting, ad decision etc. An inventory represents a place (a mobile screen, a web page, etc.) where your ads will be displayed. Common inventories in retail marketplaces include Home, Product detail page (PDP), Search Result Page (SRP), Category page, Checkout page.
      "num_ads": 0,  // Number of ads requested for the inventory. The sum of this value for inventories requested together cannot exceed 200.
      "inventory_items": [  // The contextual item information. e.g., An item being shown in a product detail page.
        {  // Item on the inventory page. e.g., Item being shown in a product detail page.
          "item_id": "ITEM_ID",
          "item_group_id": "ITEM_GROUP_ID"
        }
      ],
      "categories": [  // Categories of the page: This contextual data is used for ML training and not for other purposes such as filtering. Each category string has a hierarchy separated by '>'. For example, 'Sports & Fitness > Athletic Clothing > Shoes' represents a category with three different levels of hierarchy.
        "CATEGORIE"
      ],
      "search_query": "SEARCH_QUERY",  // Search query string. It should be provided if the page of serving inventory is a search result page.
      "search_metadata": {  // Metadata of the search query. This field can be used to provide additional information about the search query which may improve the response quality of the search inventories.
        "synonyms": [  // Synonyms of the search query. For the search query 'car' as an example, a client can put the synonyms in this field like `'synonyms': ['vehicle', 'automobile']`.
          "SYNONYM"
        ]
      },
      "custom_item_pool": {  // Using this field requires internal setup for the inventory so please contact your representative before using this.
        "items": [  // Items in the pool.
          {  // Information of the item from the pool.
            "id": "ID",  // Required. ID of the item.
            "context": {
              "shipping_charge": {},  // A monetary amount in a specific currency; the unit is micro at fixed point value for accurate accumulation operation.
              "distance": 0,  // Distance to the user from where this specific item is located. There is no requirement on the unit of distance as long as the implied unit is consistently used when communicating with Moloco.
              "discount": {}  // Discount from the original price defined either using rate or a price amount, or both.
            },
            "score": {
              "quality_score": 0  // Platform-defined quality score for items in the pool, based on its relevance to the request. To use this feature, each item in the custom item pool requires this score, between 0 and 1, which helps determine the adRank.
            }
          }
        ]
      },
      "filtering": {  // This field is used to filter ads based on a variety of criteria. Multiple filtering criteria are considered in an AND relationship. This means that an ad must meet all of the filtering criteria in order to be displayed. We support up to 5 simultaneous filtering criteria.
        "category": {  // This field is used to filter ads based on categories.
          "operator": "OPERATOR",
          "categories": [  // Required. Only ads matching the given category filtering option will be served.
            "CATEGORIE"
          ]
        },
        "location": {  // This field is used to filter ads based on locations.
          "locations": [  // Each location is defined using a multi-level hierarchy, such as US>CA>Redwood. The list of locations provided is combined using OR logic to form a union, which is then used for location-based filtering. For example, if an ad is configured to show only to users in US > CA, and the incoming location values are {'US>CA', 'US>WA'}, the ad will match. However, if the values are {'US>NY', 'US>WA'}, the ad will not match because neither of them meets the filter condition.
            "LOCATION"
          ]
        },
        "brand": {  // This field is used to filter ads based on brand.
          "brand_ids": [  // Required. Only ads matching any of the given brand ids will be served. Please provide only one of brand_id or brand_ids.
            "BRAND_ID"
          ]
        },
        "delivery": {  // This field is used to filter ads based on delivery.
          "delivery_options": [  // Required. Only ads matching any of the given delivery options will be served. Please provide only one of delivery_option or delivery_options.
            "DELIVERY_OPTION"
          ]
        },
        "price": {  // This field is used to filter ads based on price.
          "min_price": 0,  // Required. Only ads with price greater than or equal to min_price will be served. Prices are in platform's default currency.
          "max_price": 0  // Required. Only ads with price less than or equal to max_price will be served. Prices are in platform's default currency.
        },
        "sale_price": {  // This field is used to filter ads based on sale price.
          "min_sale_price": 0,  // Required. Only ads with sale price greater than or equal to min_sale_price will be served. Prices are in platform's default currency.
          "max_sale_price": 0  // Required. Only ads with sale price less than or equal to max_sale_price will be served. Prices are in platform's default currency.
        },
        "rating": {  // This field is used to filter ads based on rating.
          "min": 0,  // Required. Only ads with rating greater than or equal to min rating will be served.
          "max": 0  // Required. Only ads with rating less than or equal to max rating will be served.
        },
        "review_count": {  // This field is used to filter ads based on review count.
          "min": 0,  // Required. Only ads with review count greater than or equal to min review_count will be served.
          "max": 0  // Required. Only ads with review count less than or equal to max review_count will be served.
        },
        "color": {  // This field is used to filter ads based on colors.
          "colors": [  // Required. Only ads matching any of the given the colors will be served.
            "COLOR"
          ]
        },
        "gender": {  // This field is used to filter ads based on genders.
          "genders": [  // Required. Only ads matching any of the given genders will be served.
            "GENDER"
          ]
        },
        "size": {  // This field is used to filter ads based on sizes.
          "sizes": [  // Required. Only ads matching any of the given sizes will be served.
            "SIZE"
          ]
        },
        "material": {  // This field is used to filter ads based on materials.
          "materials": [  // Required. Only ads matching any of the given materials will be served.
            "MATERIAL"
          ]
        },
        "pattern": {  // This field is used to filter ads based on patterns.
          "patterns": [  // Required. Only ads matching any of the given patterns will be served.
            "PATTERN"
          ]
        },
        "condition": {  // This field is used to filter ads based on conditions.
          "conditions": [  // Required. Only ads matching any of the given conditions will be served.
            "CONDITION"
          ]
        },
        "age_group": {  // This field is used to filter ads based on age groups.
          "age_groups": [  // Required. Only ads matching any of the given age groups will be served.
            "AGE_GROUP"
          ]
        }
      }
    }
  ],
  "channel_type": "CHANNEL_TYPE",  // ChannelType enumerates available channel types. Simply using APP and SITE is fine, but you can also further distinguish DESKTOP_SITE and MOBILE_SITE for web users.
  "domain": "DOMAIN",  // Set domain to a value that can identify the domain portion of your website's URL. We recommend you keep the same value across your website and application if they share your backend.
  "page_id": "PAGE_ID",  // ID of the page where the ads will be displayed. It is a mandatory field if the Ad Placement (Inventory) is configured to use the PAGE_VIEW event type. 
  "deduplication_setting": {  // The response deduplication setting for this decision request.
    "per_request": {
      "method": "METHOD",  // Deduplication method.
      "criteria": "CRITERIA"  // Deduplication criteria.
    }
  },
  "response_setting": {
    "campaign_metadata_fields": [
      "CAMPAIGN_METADATA_FIELD"
    ]
  }
}

